const PROCESSING_FEE = 5;
const RUNE_BASE_PREMIUM = 25;

export function runScenario(scenario: unknown): unknown {
  const s = scenario as { steps: { op: string; items: unknown[] }[] };
  const items = s.steps[0].items;
  return { results: [{ premium: items.length * RUNE_BASE_PREMIUM + PROCESSING_FEE }] };
}
